PROCEDURE ClearData IS
BEGIN
    DELETE FROM Ports;
    --Перенос данных перед удалением
    INSERT INTO temp_cruises SELECT * FROM Cruises;
    DELETE FROM Cruises;
    COMMIT;
    EXCEPTION
        WHEN OTHERS THEN
        ROLLBACK;
        RAISE_APPLICATION_ERROR(-20002, 'Failed to clear tables', TRUE);
END ClearData;



    PROCEDURE DeleteCruise(p_cr_id IN INT) IS
    BEGIN
        -- Перенос данных перед удалением
        INSERT INTO temp_cruises SELECT * FROM Cruises WHERE cr_id = p_cr_id;
        DELETE FROM Cruises WHERE cr_id = p_cr_id;
        COMMIT;
        EXCEPTION
            WHEN OTHERS THEN
                RAISE_APPLICATION_ERROR(-20003, 'Failed to delete cruise', TRUE);
    END DeleteCruise;
END CruiseDataPackage;
